+
+    let verdict = if hard_fail_triggered {
+        Verdict::Fail
+    } else if any_rule_failed || !meets_weighted {
+        Verdict::Hold
+    } else {
+        Verdict::Pass
+    };
+
+    EvaluationResult {
+        run_id: deterministic_run_id(
+            fixture.criteria_version.as_str(),
+            bundle.artifact_bundle_id.as_str(),
